mapper.insert:

			SELECT 'FIL-' || TO_CHAR(SYSDATE, 'YYMMDD') || '_' || 
               (SELECT NVL(MAX(TO_NUMBER(SUBSTR(file_id, 12))), 0) + 1
                FROM files 
                WHERE file_id LIKE 'FIL-' || TO_CHAR(SYSDATE, 'YYMMDD') || '_%')
        	FROM DUAL

		INSERT INTO files (
							file_id
							, task_id
							, post_id
							, logical_name
							, is_deleted
							, created_at
						   )
		VALUES(
				#{fileId}
				, #{fileId}
				, #{postId}
				, #{logicalName}
				, #{isDeleted}
				, #{createdAt}
			  )


    SELECT 'VER-' || TO_CHAR(SYSDATE, 'YYMMDD') || '_' ||
           (SELECT NVL(MAX(TO_NUMBER(SUBSTR(version_id, 12))), 0) + 1
            FROM file_versions
            WHERE version_id LIKE 'VER-' || TO_CHAR(SYSDATE, 'YYMMDD') || '_%')
    FROM DUAL

INSERT INTO file_versions (
                            version_id
                          	, file_id
                          	, version_number
                          	, file_path
                          	, file_size
                          	, uploader
                          	, uploaded_at
                          	, saved_name
                          )
VALUES (
         #{versionId}
       	 , #{fileId}
       	 , #{versionNumber}
       	 , #{filePath}
       	 , #{fileSize}
         , #{uploader}
       	 , #{uploadedAt}
       	 , #{savedName}
       )
